/**
 * Generate Sentry firewall config.
 *
 * Data source: https://docs.sentry.io/api/auth/
 *
 * Sentry uses Bearer token authentication via Authorization header.
 * No documented token format; using generic alphanumeric placeholder.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.sentry.io/api/auth/";
// No documented format; generic 32-char alphanumeric
const PLACEHOLDER_VALUE = "Vm0PlaceHolder00000000000000000a";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Sentry API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:sentry",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const sentryFirewall: FirewallConfig = {",
    '  name: "sentry",',
    '  description: "Sentry API",',
    "  placeholders: {",
    `    SENTRY_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://sentry.io/api",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.SENTRY_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "};",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Sentry firewall config...");
  const ts = generateTypeScript();
  writeOutput("sentry", ts, import.meta.dirname);
}
